  RENDER_SID: 'srv-d7t9ivreo5us73ftose0',
  API: 'https://api.ivxholding.com',
};

function fetch2(url, opts = {}) {
  return new Promise((resolve) => {
    const u = new URL(url);
    const lib = u.protocol === 'https:' ? https : http;
    const req = lib.request(url, { method: opts.method || 'GET', headers: opts.headers || {}, timeout: 30000 }, (res) => {
      let body = '';
      res.on('data', d => body += d);
      res.on('end', () => resolve({ status: res.statusCode, body, headers: res.headers }));
    });
    req.on('error', e => resolve({ status: 0, error: e.message }));
    req.on('timeout', () => { req.destroy(); resolve({ status: 0, error: 'timeout' }); });
    if (opts.body) req.write(opts.body);
    req.end();
  });
}

const out = { start: new Date().toISOString(), phases: {} };

// ===== PHASE 1: BACKEND HEALTH =====
console.log('=== PHASE 1: Backend Health ===');
const health = await fetch2(`${ENV.API}/health`);
const healthData = health.body ? JSON.parse(health.body) : {};
out.phases.health = { status: health.status, commit: healthData.commit, bootTime: healthData.bootTime, service: healthData.service, routeCount: healthData.routeCount };
console.log('Health:', health.status, healthData.commit, healthData.bootTime);

// Version
const ver = await fetch2(`${ENV.API}/version`);
const verData = ver.body ? JSON.parse(ver.body) : {};
out.phases.version = { status: ver.status, commit: verData.commit };
console.log('Version:', ver.status, verData.commit);

// ===== PHASE 2: SUPABASE AUTH + DB TABLES =====
console.log('\n=== PHASE 2: Supabase Auth + DB ===');
// Sign in as owner
const signInRes = await fetch2(`https://${ENV.SUPABASE_URL}/auth/v1/token?grant_type=password`, {
  method: 'POST',
  headers: { 'apikey': ENV.SUPABASE_ANON, 'Content-Type': 'application/json' },
  body: JSON.stringify({ email: ENV.OWNER_EMAIL, password: ENV.OWNER_PASSWORD })
});
let ownerSession = null;
try { ownerSession = JSON.parse(signInRes.body); } catch {}
out.phases.supabaseOwner = { status: signInRes.status, signInOk: !!ownerSession?.access_token, userId: ownerSession?.user?.id, email: ownerSession?.user?.email };
console.log('Owner sign-in:', signInRes.status, ownerSession?.user?.email);

// List all auth users via service role
const usersRes = await fetch2(`https://${ENV.SUPABASE_URL}/auth/v1/admin/users`, {
  headers: { 'apikey': ENV.SUPABASE_SERVICE, 'Authorization': `Bearer ${ENV.SUPABASE_SERVICE}` }
});
let allUsers = [];
try { allUsers = JSON.parse(usersRes.body); } catch {}
out.phases.allAuthUsers = { count: allUsers.length, users: allUsers.map(u => ({ id: u.id, email: u.email, created: u.created_at, confirmed: u.email_confirmed_at, banned: u.banned_until })) };
console.log('Auth users count:', allUsers.length);

// List all DB tables via service role
const tablesRes = await fetch2(`https://${ENV.SUPABASE_URL}/rest/v1/information_schema/tables?table_schema=eq.public&select=table_name`, {
  headers: { 'apikey': ENV.SUPABASE_SERVICE, 'Authorization': `Bearer ${ENV.SUPABASE_SERVICE}` }
});
let tables = [];
try { tables = JSON.parse(tablesRes.body).map(t => t.table_name); } catch {}
out.phases.tables = tables;
console.log('Tables:', tables.join(', '));

// ===== Count rows in every business table =====
const businessTables = ['members','investors','buyers','jv_deals','private_lenders','tokenized_assets','wallets','treasury','ledger','wire_transfers','withdrawals','kyc','notifications','capital_accounts','distributions'];
out.phases.tableCounts = {};
for (const t of businessTables) {
  if (!tables.includes(t)) { out.phases.tableCounts[t] = { exists: false }; continue; }
  const cRes = await fetch2(`https://${ENV.SUPABASE_URL}/rest/v1/${t}?select=count`, {
    headers: { 'apikey': ENV.SUPABASE_SERVICE, 'Authorization': `Bearer ${ENV.SUPABASE_SERVICE}`, 'Range': '0-0', 'Prefer': 'count=exact' }
  });
  const range = cRes.headers?.['content-range'] || cRes.headers?.['Content-Range'] || '';
  const count = range.includes('/') ? parseInt(range.split('/')[1]) : null;
  out.phases.tableCounts[t] = { exists: true, count, status: cRes.status };
  console.log(`  ${t}: ${count}`);
}

// ===== Sample data from each table to identify fake/test data =====
out.phases.sampleData = {};
for (const t of ['members','investors','buyers','jv_deals','private_lenders','tokenized_assets','wallets','withdrawals','wire_transfers']) {
  if (!tables.includes(t)) continue;
  const sRes = await fetch2(`https://${ENV.SUPABASE_URL}/rest/v1/${t}?select=*&limit=50`, {
    headers: { 'apikey': ENV.SUPABASE_SERVICE, 'Authorization': `Bearer ${ENV.SUPABASE_SERVICE}` }
  });
  let rows = [];
  try { rows = JSON.parse(sRes.body); } catch {}
  out.phases.sampleData[t] = rows;
}

// ===== PHASE 3: GITHUB =====
console.log('\n=== PHASE 3: GitHub ===');
const ghUser = await fetch2('https://api.github.com/user', {
  headers: { 'Authorization': `Bearer ${ENV.GITHUB_TOKEN}`, 'Accept': 'application/vnd.github+json', 'User-Agent': 'IVX-Audit' }
});
let ghUserData = {}; try { ghUserData = JSON.parse(ghUser.body); } catch {}
out.phases.github = { status: ghUser.status, user: ghUserData.login };

const ghRepo = await fetch2('https://api.github.com/repos/ibb142/rork-global-real-estate-invest', {
  headers: { 'Authorization': `Bearer ${ENV.GITHUB_TOKEN}`, 'Accept': 'application/vnd.github+json', 'User-Agent': 'IVX-Audit' }
});
