out.phases.githubRepo = { status: ghRepo.status, fullName: ghRepoData.full_name, private: ghRepoData.private, defaultBranch: ghRepoData.default_branch, pushedAt: ghRepoData.pushed_at };

const ghCommit = await fetch2('https://api.github.com/repos/ibb142/rork-global-real-estate-invest/commits/main`,', {
  headers: { 'Authorization': `Bearer ${ENV.GITHUB_TOKEN}`, 'Accept': 'application/vnd.github+json', 'User-Agent': 'IVX-Audit' }
});
let ghCommitData = {}; try { ghCommitData = JSON.parse(ghCommit.body); } catch {}
out.phases.githubCommit = { status: ghCommit.status, sha: ghCommitData.sha, message: ghCommitData.commit?.message, date: ghCommitData.commit?.author?.date };
console.log('GitHub commit:', ghCommitData.sha, ghCommitData.commit?.message);

// ===== PHASE 4: RENDER =====
console.log('\n=== PHASE 4: Render ===');
const rdService = await fetch2(`https://api.render.com/v1/services/${ENV.RENDER_SID}`, {
  headers: { 'Authorization': `Bearer ${ENV.RENDER_KEY}`, 'Accept': 'application/json' }
});
