  headers: { 'Authorization': `Bearer ${ENV.RENDER_KEY}`, 'Accept': 'application/json' }
});
let rdData = {}; try { rdData = JSON.parse(rdService.body); } catch {}
out.phases.renderService = { status: rdService.status, name: rdData.name, suspended: rdData.suspended, serviceId: rdData.id };
console.log('Render service:', rdService.status, rdData.name, rdData.suspended);

const rdDeploys = await fetch2(`https://api.render.com/v1/services/${ENV.RENDER_SID}/deploys?limit=3`, {
  headers: { 'Authorization': `Bearer ${ENV.RENDER_KEY}`, 'Accept': 'application/json' }
});
let rdDeploysData = []; try { rdDeploysData = JSON.parse(rdDeploys.body); } catch {}
out.phases.renderDeploys = rdDeploysData.map(d => ({ id: d.id, commit: d.commit?.id, status: d.status, createdAt: d.createdAt, finishedAt: d.finishedAt }));
console.log('Render deploys:', out.phases.renderDeploys.length);
out.phases.renderDeploys.forEach(d => console.log(`  ${d.id} — ${d.status} — ${d.commit} — ${d.createdAt}`));

// ===== PHASE 5: OWNER AI LIVE =====
console.log('\n=== PHASE 5: Owner AI Live ===');
const ownerAI = await fetch2(`${ENV.API}/api/ivx/owner-ai`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${ENV.OWNER_TOKEN}` },
  body: JSON.stringify({ message: 'What is your name?', conversationId: 'audit-identity-' + Date.now() })
});
let ownerAIData = {}; try { ownerAIData = JSON.parse(ownerAI.body); } catch {}
out.phases.ownerAI_identity = { status: ownerAI.status, answer: (ownerAIData.answer || ownerAIData.message || ownerAI.body || '').slice(0, 500), blocked: ownerAIData.blocked };
console.log('Owner AI name:', ownerAI.status, (ownerAIData.answer || '').slice(0, 200));

const ownerAI2 = await fetch2(`${ENV.API}/api/ivx/owner-ai`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${ENV.OWNER_TOKEN}` },
  body: JSON.stringify({ message: 'Who created you and who is the owner of IVXHOLDINGS?', conversationId: 'audit-owner-' + Date.now() })
});
let ownerAI2Data = {}; try { ownerAI2Data = JSON.parse(ownerAI2.body); } catch {}
out.phases.ownerAI_owner = { status: ownerAI2.status, answer: (ownerAI2Data.answer || ownerAI2Data.message || ownerAI2.body || '').slice(0, 500) };
console.log('Owner AI owner:', ownerAI2.status, (ownerAI2Data.answer || '').slice(0, 200));

// ===== PHASE 6: PUBLIC CHAT =====
console.log('\n=== PHASE 6: Public Chat ===');
const pubChat = await fetch2(`${ENV.API}/api/ivx/public-chat`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ message: 'Tell me about IVXHOLDINGS investments', conversationId: 'audit-pub-' + Date.now() })
});
let pubChatData = {}; try { pubChatData = JSON.parse(pubChat.body); } catch {}
out.phases.publicChat = { status: pubChat.status, answer: (pubChatData.answer || pubChatData.message || pubChat.body || '').slice(0, 500) };
console.log('Public chat:', pubChat.status, (pubChatData.answer || '').slice(0, 200));

// ===== PHASE 7: LANDING =====
console.log('\n=== PHASE 7: Landing Page ===');
const landing = await fetch2('https://chat.ivxholding.com');
out.phases.landing = { status: landing.status, bodyLen: landing.body.length, hasContent: landing.body.length > 1000 };
console.log('Landing:', landing.status, landing.body.length, 'bytes');

// ===== PHASE 8: SENIOR DEV BRAIN =====
console.log('\n=== PHASE 8: Senior Dev Brain ===');
const sdBrain = await fetch2(`${ENV.API}/api/ivx/owner-ai-senior-dev-brain`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${ENV.OWNER_TOKEN}` },
  body: JSON.stringify({ message: 'What can you do as a senior developer?', conversationId: 'audit-sd-' + Date.now() })
});
let sdBrainData = {}; try { sdBrainData = JSON.parse(sdBrain.body); } catch {}
out.phases.seniorDevBrain = { status: sdBrain.status, answer: (sdBrainData.answer || sdBrainData.message || sdBrain.body || '').slice(0, 500), blocked: sdBrainData.blocked };
console.log('Senior dev brain:', sdBrain.status, (sdBrainData.answer || '').slice(0, 200));

out.end = new Date().toISOString();
console.log('\n=== DONE ===');
const fs = await import('node:fs');
fs.writeFileSync('/tmp/ivx-audit-results.json', JSON.stringify(out, null, 2));
console.log('Results saved to /tmp/ivx-audit-results.json');
