import https from 'node:https';

const ENV = {
  SU: 'kvclcdjmjghndxsngfzb.supabase.co',
  ANON: 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt2Y2xjZGptamdobmR4c25nZnpiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzMxOTQwMjcsImV4cCI6MjA4ODc3MDAyN30.OLDwa21VHQNs151AD-8k--_HigQ2d-N7yJfFn5UeNPk',
  SR: 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt2Y2xjZGptamdobmR4c25nZnpiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MzE5NDAyNywiZXhwIjoyMDg4NzcwMDI3fQ.TaTRyViK-8sv3R_g1Me08sEjnyMskGXKF0u-I-PTaQ8',
  EMAIL: 'iperez4242@gmail.com',
  PASS: 'X146corp@1x146corp$$1',
  TOKEN: 'b8d6f01528fe515ead5390d3c408ea79b2b34c3f39eefebc004efdc02734284b',
  GH: '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',
  RK: 'rnd_1H0XCquMZQTRyAnHgbEv8dVWYPVs',
  RSID: 'srv-d7t9ivreo5us73ftose0',
  API: 'https://api.ivxholding.com',
};

function f(url, opts={}) {
  return new Promise((resolve) => {
    const req = https.request(url, { method: opts.method||'GET', headers: opts.headers||{}, timeout: 30000 }, (res) => {
      let body=''; res.on('data',d=>body+=d); res.on('end',()=>resolve({status:res.statusCode,body,headers:res.headers}));
    });
    req.on('error',e=>resolve({status:0,error:e.message}));
    req.on('timeout',()=>{req.destroy();resolve({status:0,error:'timeout'})});
    if(opts.body) req.write(opts.body); req.end();
  });
}

const out = { start: new Date().toISOString(), phases: {} };

// 1. Health + version
const health = await f(`${ENV.API}/health`);
const hd = JSON.parse(health.body||'{}');
out.health = { status: health.status, commit: hd.commit, bootTime: hd.bootTime, routeCount: hd.routeCount };

// 2. Supabase owner sign-in
const si = await f(`https://${ENV.SU}/auth/v1/token?grant_type=password`, {
  method:'POST', headers:{'apikey':ENV.ANON,'Content-Type':'application/json'},
  body: JSON.stringify({email:ENV.EMAIL,password:ENV.PASS})
});
const sess = JSON.parse(si.body||'{}');
out.ownerSignIn = { status: si.status, ok: !!sess.access_token, email: sess.user?.email, userId: sess.user?.id };

// 3. Auth users (with page param for >1000)
const usersRes = await f(`https://${ENV.SU}/auth/v1/admin/users?per_page=1000`, {
  headers: { 'apikey': ENV.SR, 'Authorization': `Bearer ${ENV.SR}` }
});
let allUsers = [];
try { const p = JSON.parse(usersRes.body); allUsers = Array.isArray(p) ? p : (p.users||[]); } catch {}
out.authUsers = allUsers.map(u => ({ id: u.id, email: u.email, confirmed: !!u.email_confirmed_at, banned: u.banned_until, created: u.created_at }));

// 4. Identify test/fake users
const realEmails = ['iperez4242@gmail.com', 'owner@ivxholding.com', 'admin@ivxholding.com', 'onestop140@yahoo.com'];
const testUsers = allUsers.filter(u => !realEmails.includes(u.email));
out.testUsersToRemove = testUsers.map(u => ({ id: u.id, email: u.email }));
out.realUsers = allUsers.filter(u => realEmails.includes(u.email)).map(u => ({ id: u.id, email: u.email, confirmed: !!u.email_confirmed_at }));
console.log(`Test users to remove: ${testUsers.length}, Real users: ${out.realUsers.length}`);

// 5. Query actual table names via PostgREST — try each known table
const knownTables = ['profiles','wallets','wallet_transactions','properties','holdings','transactions','jv_deals','landing_deals','waitlist','notifications','analytics_events','analytics_dashboard','analytics_kpi','analytics_retention','analytics_investments','conversations','messages','conversation_participants','landing_analytics','landing_investments','market_data','market_index','lenders','buyers','private_lenders','tokenized_assets','treasury','ledger','wire_transfers','withdrawals','capital_accounts','distributions','kyc_verifications','kyc_documents','visitor_sessions','live_sessions','realtime_audit','ivx_knowledge_documents','landing_page_config','landing_deployments','landing_submissions','email_notifications_queue','waitlist_entries','waitlist_otp_events','orders'];
out.tableCounts = {};
for (const t of knownTables) {
  const r = await f(`https://${ENV.SU}/rest/v1/${t}?select=count`, {
    headers: { 'apikey': ENV.SR, 'Authorization': `Bearer ${ENV.SR}`, 'Range': '0-0', 'Prefer': 'count=exact' }
  });
  const range = r.headers?.['content-range'] || '';
  const count = range.includes('/') ? parseInt(range.split('/')[1]) : null;
  if (r.status < 400) {
    out.tableCounts[t] = { exists: true, count, status: r.status };
    console.log(`  ${t}: ${count} rows (HTTP ${r.status})`);
  }
}

// 6. Sample data from key tables
out.sampleData = {};
for (const t of ['profiles','wallets','jv_deals','waitlist','transactions','conversations','messages','landing_investments','landing_analytics']) {
  if (!out.tableCounts[t]?.exists) continue;
  const r = await f(`https://${ENV.SU}/rest/v1/${t}?select=*&limit=50`, {
    headers: { 'apikey': ENV.SR, 'Authorization': `Bearer ${ENV.SR}` }
  });
  try { out.sampleData[t] = JSON.parse(r.body); } catch { out.sampleData[t] = r.body.slice(0,200); }
}

// 7. GitHub
const ghC = await f('https://api.github.com/repos/ibb142/rork-global-real-estate-invest/commits/main', {
  headers: { 'Authorization': `Bearer ${ENV.GH}`, 'Accept': 'application/vnd.github+json', 'User-Agent': 'IVX-Audit' }
});
const ghCD = JSON.parse(ghC.body||'{}');
out.github = { sha: ghCD.sha, message: ghCD.commit?.message, date: ghCD.commit?.author?.date };

// 8. Render deploys
const rdD = await f(`https://api.render.com/v1/services/${ENV.RSID}/deploys?limit=5`, {
  headers: { 'Authorization': `Bearer ${ENV.RK}`, 'Accept': 'application/json' }
});
try { out.renderDeploys = JSON.parse(rdD.body).map(d => ({ id: d.id, commit: d.commit?.id?.slice(0,8), status: d.status, createdAt: d.createdAt, finishedAt: d.finishedAt })); } catch { out.renderDeploys = rdD.body.slice(0,300); }

// 9. Public chat (correct URL)
const pubChat = await f(`${ENV.API}/api/public/chat`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ message: 'Tell me about IVXHOLDINGS investments', conversationId: 'audit-pub-' + Date.now() })
});
let pcData = {}; try { pcData = JSON.parse(pubChat.body); } catch {}
out.publicChat = { status: pubChat.status, answer: (pcData.answer || pcData.message || pcData.reply || pubChat.body || '').slice(0, 400) };
console.log('Public chat:', pubChat.status, (pcData.answer || pcData.reply || '').slice(0, 150));

// 10. Senior dev status (correct URL)
const sdStatus = await f(`${ENV.API}/api/ivx/senior-developer/status`, {
  headers: { 'Authorization': `Bearer ${ENV.TOKEN}` }
});
let sdData = {}; try { sdData = JSON.parse(sdStatus.body); } catch {}
out.seniorDevStatus = { status: sdStatus.status, data: sdData };
console.log('Senior dev status:', sdStatus.status);

// 11. Senior dev credential audit
const sdCred = await f(`${ENV.API}/api/ivx/senior-developer/credential-audit`, {
  headers: { 'Authorization': `Bearer ${sess.access_token || ENV.TOKEN}` }
});
let sdCredData = {}; try { sdCredData = JSON.parse(sdCred.body); } catch {}
out.seniorDevCredAudit = { status: sdCred.status, ok: sdCredData.ok, blockers: sdCredData.blockers, ownerVerified: sdCredData.ownerVerified };
console.log('Senior dev cred audit:', sdCred.status, sdCredData.ok);

// 12. Landing page
const landing = await f('https://chat.ivxholding.com');
out.landing = { status: landing.status, bodyLen: landing.body.length, bodyPreview: landing.body.slice(0, 300) };
console.log('Landing:', landing.status, landing.body.length, 'bytes');

// 13. Owner AI — regular conversation question
const ai1 = await f(`${ENV.API}/api/ivx/owner-ai`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${ENV.TOKEN}` },
  body: JSON.stringify({ message: 'What is 2+2?', conversationId: 'audit-math-' + Date.now() })
});
let ai1Data = {}; try { ai1Data = JSON.parse(ai1.body); } catch {}
out.ownerAI_math = { status: ai1.status, answer: (ai1Data.answer || '').slice(0, 200), blocked: ai1Data.blocked };
console.log('Owner AI math:', ai1.status, (ai1Data.answer || '').slice(0, 100));

// 14. Owner AI — IVXHOLDINGS investment question
const ai2 = await f(`${ENV.API}/api/ivx/owner-ai`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${ENV.TOKEN}` },
  body: JSON.stringify({ message: 'Tell me about IVXHOLDINGS investment opportunities', conversationId: 'audit-inv-' + Date.now() })
});
let ai2Data = {}; try { ai2Data = JSON.parse(ai2.body); } catch {}
out.ownerAI_investments = { status: ai2.status, answer: (ai2Data.answer || '').slice(0, 400), blocked: ai2Data.blocked };
console.log('Owner AI investments:', ai2.status, (ai2Data.answer || '').slice(0, 150));

// 15. Member registration endpoint
const regTest = await f(`${ENV.API}/api/members/register`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ email: '__test_audit_only__@ivxholding.com', password: 'TestAudit123!', firstName: 'Audit', lastName: 'Test' })
});
out.memberReg = { status: regTest.status, body: regTest.body.slice(0, 200) };
console.log('Member registration:', regTest.status);

// 16. Landing config
const lc = await f(`${ENV.API}/api/landing-config`);
let lcData = {}; try { lcData = JSON.parse(lc.body); } catch {}
out.landingConfig = { status: lc.status, hasData: !!lcData && Object.keys(lcData).length > 0 };
console.log('Landing config:', lc.status);

out.end = new Date().toISOString();
const fs = await import('node:fs');
fs.writeFileSync('/tmp/ivx-audit-results2.json', JSON.stringify(out, null, 2));
console.log('\n=== FULL AUDIT DONE ===');
AUDIT_EOF
