const sql = `
-- Wire Transfers
CREATE TABLE IF NOT EXISTS public.wire_transfers (
  id TEXT PRIMARY KEY,
  user_id UUID,
  deal_id TEXT,
  amount NUMERIC DEFAULT 0,
  currency TEXT DEFAULT 'USD',
  status TEXT DEFAULT 'pending',
  bank_name TEXT,
  bank_account_last4 TEXT,
  routing_number TEXT,
  swift_code TEXT,
  reference TEXT,
  initiated_at TIMESTAMPTZ,
  completed_at TIMESTAMPTZ,
  approved_by UUID,
  approved_at TIMESTAMPTZ,
  rejection_reason TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);
ALTER TABLE public.wire_transfers ENABLE ROW LEVEL SECURITY;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname='wire_transfers_auth_all') THEN
    CREATE POLICY "wire_transfers_auth_all" ON public.wire_transfers FOR ALL TO authenticated USING (true) WITH CHECK (true);
  END IF;
END $$;
CREATE INDEX IF NOT EXISTS idx_wire_transfers_user ON public.wire_transfers(user_id);
CREATE INDEX IF NOT EXISTS idx_wire_transfers_status ON public.wire_transfers(status);

-- Withdrawals
CREATE TABLE IF NOT EXISTS public.withdrawals (
  id TEXT PRIMARY KEY,
  user_id UUID NOT NULL,
  wallet_id UUID,
  amount NUMERIC NOT NULL DEFAULT 0,
  currency TEXT DEFAULT 'USD',
  status TEXT DEFAULT 'pending',
  payment_method TEXT,
  bank_account_last4 TEXT,
  crypto_address TEXT,
  fee NUMERIC DEFAULT 0,
  net_amount NUMERIC DEFAULT 0,
  requested_at TIMESTAMPTZ DEFAULT now(),
  processed_at TIMESTAMPTZ,
  approved_by UUID,
  approved_at TIMESTAMPTZ,
  rejected_at TIMESTAMPTZ,
  rejection_reason TEXT,
  two_person_approval BOOLEAN DEFAULT false,
  second_approver UUID,
  second_approved_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now(),
  CONSTRAINT withdrawals_status_check CHECK (status IN ('pending','approved','processing','completed','rejected','cancelled'))
);
ALTER TABLE public.withdrawals ENABLE ROW LEVEL SECURITY;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname='withdrawals_auth_all') THEN
    CREATE POLICY "withdrawals_auth_all" ON public.withdrawals FOR ALL TO authenticated USING (true) WITH CHECK (true);
  END IF;
END $$;
CREATE INDEX IF NOT EXISTS idx_withdrawals_user ON public.withdrawals(user_id);
CREATE INDEX IF NOT EXISTS idx_withdrawals_status ON public.withdrawals(status);

-- Treasury
CREATE TABLE IF NOT EXISTS public.treasury (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  account_name TEXT NOT NULL,
  account_type TEXT DEFAULT 'operating',
  balance NUMERIC DEFAULT 0,
  currency TEXT DEFAULT 'USD',
  bank_name TEXT,
  bank_account_last4 TEXT,
  routing_number TEXT,
  is_active BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);
ALTER TABLE public.treasury ENABLE ROW LEVEL SECURITY;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname='treasury_auth_all') THEN
    CREATE POLICY "treasury_auth_all" ON public.treasury FOR ALL TO authenticated USING (true) WITH CHECK (true);
  END IF;
END $$;

-- Ledger (immutable)
CREATE TABLE IF NOT EXISTS public.ledger (
  id TEXT PRIMARY KEY,
  user_id UUID,
  deal_id TEXT,
  type TEXT NOT NULL,
  direction TEXT NOT NULL DEFAULT 'credit',
  amount NUMERIC NOT NULL DEFAULT 0,
  currency TEXT DEFAULT 'USD',
  balance_after NUMERIC DEFAULT 0,
  reference_id TEXT,
  reference_type TEXT,
  description TEXT,
  metadata JSONB DEFAULT '{}'::jsonb,
  immutable BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT now(),
  CONSTRAINT ledger_direction_check CHECK (direction IN ('credit','debit'))
);
ALTER TABLE public.ledger ENABLE ROW LEVEL SECURITY;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname='ledger_auth_all') THEN
    CREATE POLICY "ledger_auth_all" ON public.ledger FOR ALL TO authenticated USING (true) WITH CHECK (true);
  END IF;
END $$;
CREATE INDEX IF NOT EXISTS idx_ledger_user ON public.ledger(user_id);
CREATE INDEX IF NOT EXISTS idx_ledger_deal ON public.ledger(deal_id);
CREATE INDEX IF NOT EXISTS idx_ledger_created ON public.ledger(created_at DESC);

-- Capital Accounts
CREATE TABLE IF NOT EXISTS public.capital_accounts (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL,
  deal_id TEXT,
  account_name TEXT,
  contributed NUMERIC DEFAULT 0,
  distributed NUMERIC DEFAULT 0,
  balance NUMERIC DEFAULT 0,
  ownership_pct NUMERIC DEFAULT 0,
  roi NUMERIC DEFAULT 0,
  status TEXT DEFAULT 'active',
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);
ALTER TABLE public.capital_accounts ENABLE ROW LEVEL SECURITY;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname='capital_accounts_auth_all') THEN
    CREATE POLICY "capital_accounts_auth_all" ON public.capital_accounts FOR ALL TO authenticated USING (true) WITH CHECK (true);
  END IF;
END $$;
CREATE INDEX IF NOT EXISTS idx_capital_accounts_user ON public.capital_accounts(user_id);
CREATE INDEX IF NOT EXISTS idx_capital_accounts_deal ON public.capital_accounts(deal_id);

-- Distributions
CREATE TABLE IF NOT EXISTS public.distributions (
  id TEXT PRIMARY KEY,
  deal_id TEXT NOT NULL,
  user_id UUID NOT NULL,
  amount NUMERIC NOT NULL DEFAULT 0,
  currency TEXT DEFAULT 'USD',
  distribution_type TEXT DEFAULT 'quarterly',
  status TEXT DEFAULT 'pending',
  paid_at TIMESTAMPTZ,
  period_start TEXT,
  period_end TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);
ALTER TABLE public.distributions ENABLE ROW LEVEL SECURITY;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname='distributions_auth_all') THEN
    CREATE POLICY "distributions_auth_all" ON public.distributions FOR ALL TO authenticated USING (true) WITH CHECK (true);
  END IF;
END $$;
CREATE INDEX IF NOT EXISTS idx_distributions_deal ON public.distributions(deal_id);
CREATE INDEX IF NOT EXISTS idx_distributions_user ON public.distributions(user_id);

-- Tokenized Assets
CREATE TABLE IF NOT EXISTS public.tokenized_assets (
  id TEXT PRIMARY KEY,
  deal_id TEXT,
  name TEXT NOT NULL,
  symbol TEXT,
  total_supply NUMERIC DEFAULT 0,
  available_supply NUMERIC DEFAULT 0,
  token_price NUMERIC DEFAULT 0,
  currency TEXT DEFAULT 'USD',
  chain TEXT DEFAULT 'ivx-internal',
  contract_address TEXT,
  metadata JSONB DEFAULT '{}'::jsonb,
  status TEXT DEFAULT 'active',
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);
ALTER TABLE public.tokenized_assets ENABLE ROW LEVEL SECURITY;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname='tokenized_assets_select_all') THEN
    CREATE POLICY "tokenized_assets_select_all" ON public.tokenized_assets FOR SELECT USING (true);
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname='tokenized_assets_auth_write') THEN
    CREATE POLICY "tokenized_assets_auth_write" ON public.tokenized_assets FOR ALL TO authenticated USING (true) WITH CHECK (true);
  END IF;
END $$;

-- Private Lenders
CREATE TABLE IF NOT EXISTS public.private_lenders (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  company TEXT,
  email TEXT,
  phone TEXT,
  lending_capacity NUMERIC DEFAULT 0,
  interest_rate NUMERIC DEFAULT 0,
  term_months INTEGER DEFAULT 12,
  collateral_required BOOLEAN DEFAULT true,
  status TEXT DEFAULT 'active',
  notes TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);
ALTER TABLE public.private_lenders ENABLE ROW LEVEL SECURITY;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname='private_lenders_auth_all') THEN
    CREATE POLICY "private_lenders_auth_all" ON public.private_lenders FOR ALL TO authenticated USING (true) WITH CHECK (true);
  END IF;
END $$;

-- Buyers
CREATE TABLE IF NOT EXISTS public.buyers (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  company TEXT,
  email TEXT,
  phone TEXT,
  buyer_type TEXT DEFAULT 'individual',
